import React, { useState } from 'react';

const language = [
    {
        lang: 'C++.png',
        proficiency: 3
    },
    {
        lang: 'Java.jpg',
        proficiency: 5
    }
];
const LanguageList = () => {
    const languageList = language.map((item)=>{
        return <img src={require(`../resources/${item.lang}`)} alt="CPlus"/>
    });
    const proficiencyList = [];
    const proficiencyPerLang = {};
    const grid = [];
    for(var i = 0; i < language.length;i++)
    {
        for(var n = 0; n < language[i].proficiency;n++)
        {
            proficiencyList.push(<div className="cell"><i className="check icon"></i></div>);
        }
        if(language[i].proficiency < 5)
        {
            const count = 5 - language[i].proficiency;
            for(var y = 0; y < count;y++)
            {
                proficiencyList.push(<div className="cell"><i></i></div>);
            }
        }
        proficiencyPerLang[language[i].lang] = proficiencyList;
        proficiencyList.splice(0,proficiencyList);
    }
    for(var x = 0; x < language.length;x++)
    {
        grid.push(
            <div className="grid assessmentContent">
                <div className="cell">
                    <div className="ui small image" style={{borderRadius:"50%",padding: "0em", maxHeight:"2rem",maxWidth:"2rem",zIndex:"5"}}>
                        { languageList[x] }
                    </div>
                </div>
                { proficiencyPerLang[language[x].lang]}
            </div>
        )
    }
    return (grid);
};

export default LanguageList;
